INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343175, 'BACK_END', 'BIZ_MEMBER_WELCOME_TITLE_8100', 'ko-KR', 'Welcome to %s', 20241123065528, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343176, 'BACK_END', 'BIZ_MEMBER_WELCOME_CONTENT_8100', 'ko-KR', 's%님, s%정식 회원이 되신 것을 축하합니다. s%을(를) 선택한 순간부터 회원님의 계정과 자산은 안전하게 보호됩니다. 저희는 전 세계 최고의 스포츠 경기, 라이브 카지노, 보드게임, 슬롯 게임 등 다양한 콘텐츠를 제공해 드리며, 간편한 예금 방식과 빠른 출금 시스템으로 언제나 안심하고 이용하실 수 있습니다.', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343177, 'BACK_END', 'BIZ_MEMBER_DEPOSIT_SUCCESS_TITLE_8100', 'ko-KR', '예금 성공 알림', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343178, 'BACK_END', 'BIZ_MEMBER_DEPOSIT_SUCCESS_CONTENT_8100', 'ko-KR', 's%님, s%s% 예금이 완료되었어요~', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343179, 'BACK_END', 'BIZ_MEMBER_WITHDRAWAL_SUCCESS_TITLE_8100', 'ko-KR', '출금 성공 알림', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343180, 'BACK_END', 'BIZ_MEMBER_WITHDRAWAL_SUCCESS_CONTENT_8100', 'ko-KR', 's%님, s%s% 출금이 완료되었어요~', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343181, 'BACK_END', 'BIZ_MEMBER_WITHDRAWAL_FAILED_TITLE_8100', 'ko-KR', '출금 실패 알림', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343182, 'BACK_END', 'BIZ_MEMBER_WITHDRAWAL_FAILED_CONTENT_8100', 'ko-KR', 's%님, 죄송합니다. 출금이 실패했어요. 문의사항이 있으시면 7*24시간 고객센터에 문의해 주세요~', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343183, 'BACK_END', 'BIZ_MEMBER_SECURITY_TITLE_8100', 'ko-KR', '보안 알림', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343184, 'BACK_END', 'BIZ_MEMBER_SECURITY_CONTENT_8100', 'ko-KR', '회원님의 계정 보안을 위해 충전/출금 관련 문의는 반드시 공식 고객센터를 통해 진행해 주세요. 사적인 거래는 절대 하지 마세요! 문의사항이 있으시면 7*24시간 고객센터에 문의해 주세요~', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206343185, 'BACK_END', 'BIZ_MEMBER_FUNDS_SECURITY_TITLE_8100', 'ko-KR', '자금 안전 알림', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347086, 'BACK_END', 'BIZ_MEMBER_FUNDS_SECURITY_CONTENT_8100', 'ko-KR', '회원님의 자금 안전을 위해 s%를 사칭한 자의 안내에 절대 응하지 마세요. 실제 입금 확인 없이 확인 을 유도하거나, 계정 비밀번호를 요구하거나, 계정을 임대하거나 판매하는 행위는 모두 위험합니다. s% 플랫폼은 절대로 이메일 등을 통해 이체를 요청하지 않습니다! 해당 행위는 해킹 시도이며, 계정 정보가 변경되어 자산 손실로 이어질 수 있습니다. 제보는 피드백 버튼을 통해 접수해 주시면 보상 혜택이 있습니다. 문의 사항은 7*24시간 고객센터로 연락해 주세요.', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347087, 'BACK_END', 'BIZ_MEMBER_VERSION_UPGRADE_TITLE_8100', 'ko-KR', '버전 업그레이드 알림', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347088, 'BACK_END', 'BIZ_MEMBER_VERSION_UPGRADE_CONTENT_8100', 'ko-KR', '더 나은 이용을 위해 새로운 버전이 업데이트되었습니다. 지금 바로 최신 버전으로 업데이트해 주세요!', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347089, 'BACK_END', 'BIZ_AGENT_WELCOME_TITLE_8100', 'ko-KR', 's% 제휴계획 가입축하', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347110, 'BACK_END', 'BIZ_AGENT_WELCOME_CONTENT_8100', 'ko-KR', 's%님, s%의 제휴 파트너가 되신 것을 진심으로 환영합니다! 최고의 리소스를 누구보다 먼저 확보하고 싶으신가요? 오직 파트너님만을 위한 프리미엄 맞춤 서비스를 원하시나요? 최신 최상급 지원 혜택이 궁금하신가요? 지금 바로 7*24시간 제휴 전담 온라인 고객센터에 문의해 주세요. 저희는 가장 신뢰할 수 있는 지원을 약속드립니다!', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347090, 'BACK_END', 'BIZ_AGENT_FUNDS_SECURITY_TITLE_8100', 'ko-KR', '자금 안전 알림', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347091, 'BACK_END', 'BIZ_AGENT_FUNDS_SECURITY_CONTENT_8100', 'ko-KR', '파트너님의 자금 안전을 위해 s%를 사칭한 자의 안내에 절대 응하지 마세요. 실제 입금 확인 없이 확인을 유도하거나, 계정 비밀번호를 요구하거나, 계정을 임대하거나 판매하는 행위는 모두 위험합니다. s% 플랫폼은 절대로 이메일 등을 통해 이체를 요청하지 않습니다! 해당 행위는 해킹 시도이며, 계정 정보가 변경되어 자산 손실로 이어질 수 있습니다. 제보는 제휴 전용 고객센터를 통해 접수해 주시면 보상 혜택이 있습니다. 문의 사항은 7*24시간 제휴 고객센터로 연락해 주세요.', 20241123065529, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347092, 'BACK_END', 'BIZ_AGENT_SECURITY_TITLE_8100', 'ko-KR', '보안 알림', 20241123065530, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347093, 'BACK_END', 'BIZ_AGENT_SECURITY_CONTENT_8100', 'ko-KR', '파트너님의 계정 보안을 위해 예금/출금 관련 문의는 반드시 제휴 전용 고객센터를 통해 진행해 주세요. 사적인 거래는 절대 하지 마세요! 문의사항이 있으시면 7*24시간 제휴 전용 고객센터에 문의해 주세요~', 20241123065530, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347094, 'BACK_END', 'BIZ_AGENT_DEPOSIT_SUCCESS_TITLE_8100', 'ko-KR', '예금 성공 알림', 20241123065530, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347095, 'BACK_END', 'BIZ_AGENT_DEPOSIT_SUCCESS_CONTENT_8100', 'ko-KR', '파트너님, s%s% 예금이 완료되었어요~', 20241123065530, NULL, NULL, NULL);
INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347096, 'BACK_END', 'BIZ_AGENT_COMMISSION_PAYMENT_SUCCESS_TITLE_8100', 'ko-KR', '수수료 지급 성공 알림', 20241123065530, NULL, NULL, NULL);
