INSERT INTO `i18n_message` (`id`, `message_type`, `message_key`, `language`, `message`, `created_time`, `updated_time`, `creator`, `updater`) VALUES (2006318659206347101, 'BACK_END', 'BIZ_AGENT_WITHDRAWAL_FAILED_CONTENT_8100', 'ko-KR', '파트너님, 죄송합니다. 출금이 실패했어요. 문의사항이 있으시면 7*24시간 제휴 전용 고객센터에 문의해 주세요~', 20241123065530, NULL, NULL, NULL);
